code = """import json
import re

# Load data
with open(locals()['var_function-call-16687228775898280162'], 'r') as f:
    users = json.load(f)

with open(locals()['var_function-call-2051564778087209685'], 'r') as f:
    reviews = json.load(f)

with open(locals()['var_function-call-1533460168214239728'], 'r') as f:
    businesses = json.load(f)

print(f"Total users: {len(users)}")
print(f"Total reviews: {len(reviews)}")
print(f"Total businesses: {len(businesses)}")

user_ids_2016 = set()
for u in users:
    if "2016" in u['yelping_since']:
        user_ids_2016.add(u['user_id'])
print(f"Users registered in 2016: {len(user_ids_2016)}")

filtered_reviews = []
for r in reviews:
    if r['user_id'] in user_ids_2016:
        filtered_reviews.append(r)
print(f"Reviews by 2016 users: {len(filtered_reviews)}")

business_cats = {}
keywords = [
    "services in the categories of ",
    "services in the category of ",
    "services in ",
    "including ",
    "destination for ",
    "seeking ",
    "fields of ",
    "selection of ",
    "category of "
]

def extract_categories(desc):
    if not desc: return []
    start_idx = -1
    used_kw_len = 0
    for kw in keywords:
        idx = desc.rfind(kw)
        if idx > start_idx:
            start_idx = idx
            used_kw_len = len(kw)
    if start_idx == -1: return []
    cat_str = desc[start_idx + used_kw_len:]
    cat_str = cat_str.strip().rstrip('.')
    cat_str = cat_str.replace("'", "")
    cat_str = re.sub(r',? and ', ', ', cat_str)
    raw_cats = [x.strip() for x in cat_str.split(',')]
    final_cats = []
    for c in raw_cats:
        words = c.split()
        valid_words = []
        for w in words:
            if w[0].islower() and w not in ['of', '&', 'at', 'in', 'for']:
                break
            valid_words.append(w.rstrip('.,;'))
        if valid_words:
            final_cats.append(" ".join(valid_words))
    return final_cats

extracted_count = 0
for b in businesses:
    bid = b['business_id']
    bref = bid.replace('businessid_', 'businessref_')
    cats = extract_categories(b['description'])
    if cats:
        business_cats[bref] = cats
        extracted_count += 1

print(f"Businesses with extracted categories: {extracted_count}")

matched_reviews = 0
for r in filtered_reviews:
    if r['business_ref'] in business_cats:
        matched_reviews += 1
print(f"Reviews matched to businesses: {matched_reviews}")

print("__RESULT__:")
print(json.dumps("debug done"))"""

